+func summarizeTaskPrompt(prompt string) string {
+	text := strings.Join(strings.Fields(prompt), " ")
+	if text == "" {
+		return "(no description)"
+	}
+	for i, r := range text {
+		switch r {
+		case '.', '!', '?':
+			return strings.TrimSpace(text[:i+1])
+		}
+	}
+	if len(text) > 120 {
+		return strings.TrimSpace(text[:117]) + "..."
+	}
+	return text
+}
