+func formatToolNamesForPrompt(names []string) string {
+	if len(names) == 0 {
+		return "none"
+	}
+	parts := make([]string, 0, len(names))
+	for _, name := range names {
+		parts = append(parts, "`"+name+"`")
+	}
+	return strings.Join(parts, ", ")
+}

